import React, { useState, useEffect } from 'react';

export default function ToastContainer() {
  const [toasts, setToasts] = useState([]);

  const addToast = (message, type = "success") => {
    const id = Date.now();
    setToasts(prev => [...prev, { id, message, type }]);
  };

  const removeToast = (id) => {
    setToasts(prev => prev.filter(t => t.id !== id));
  };

  return (
    <div className="flex flex-col gap-2 items-center">
      {/* Test Buttons */}
      <div className="flex gap-2 mb-6">
        <button onClick={() => addToast("Successfully saved!", "success")} className="px-3 py-1.5 bg-green-500 text-white rounded text-sm">Success</button>
        <button onClick={() => addToast("Failed to fetch data.", "error")} className="px-3 py-1.5 bg-red-500 text-white rounded text-sm">Error</button>
      </div>

      {/* Portal Container */}
      <div className="fixed top-4 right-4 z-50 flex flex-col gap-2 w-80">
        {toasts.map((toast) => (
          <ToastItem key={toast.id} toast={toast} onClose={removeToast} />
        ))}
      </div>
    </div>
  );
}

function ToastItem({ toast, onClose }) {
  useEffect(() => {
    const timer = setTimeout(() => onClose(toast.id), 4000);
    return () => clearTimeout(timer);
  }, [toast, onClose]);

  const typeStyles = {
    success: "bg-green-50 text-green-800 border-green-200",
    error: "bg-red-50 text-red-800 border-red-200",
    info: "bg-blue-50 text-blue-800 border-blue-200",
    warning: "bg-yellow-50 text-yellow-800 border-yellow-200"
  };

  return (
    <div className={`flex items-center justify-between p-4 border rounded-xl shadow-lg transition duration-300 animate-slide-in ${typeStyles[toast.type]}`}>
      <span className="text-sm font-medium">{toast.message}</span>
      <button onClick={() => onClose(toast.id)} className="text-gray-400 hover:text-gray-600 ml-4 focus:outline-none">
        <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>
      </button>
    </div>
  );
}
